INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (35, '美团发布基于 N-gram 全新模型：嵌入扩展新范式，实现轻量化 MoE 高效进化', 'LongCat-Flash-Lite是一款拥有 685 亿参数，每次推理仅激活 29 亿~ 45 亿参数的轻量化 MoE 模型。通过将超过 300 亿参数高效用于嵌入层，LongCat-Flash-Lite 不仅超越了参数量等效的 MoE 基线模型，还在与同规模现有模型的对比中展现出卓越的竞争力，尤其在智能体与代码领域表现突出。', 'LongCat-Flash-Lite是一款拥有 685 亿参数，每次推理仅激活 29 亿~ 45 亿参数的轻量化 MoE 模型。通过将超过 300 亿参数高效用于嵌入层，LongCat-Flash-Lite 不仅超越了参数量等效的 MoE 基线模型，还在与同规模现有模型的对比中展现出卓越的竞争力，尤其在智能体与代码领域表现突出。', 6, '美团技术团队', 'https://tech.meituan.com/2026/02/10/longcat-flash-lite.html', '美团技术团队', 'blog', '["\u540e\u7aef", "\u6280\u672f", "\u67b6\u6784"]', '2026-02-10 00:00:00.000000', '2026-04-07 04:26:49.832457', 'https://tech.meituan.com/2026/02/10/longcat-flash-lite.html', 0.0, 0);
