INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (38, '美团 EvoCUA 刷新开源 SOTA，会用电脑还会持续进化的智能体！', '美团技术团队推出了 EvoCUA 模型并在 Github、Huggingface 开源，通过构建可验证数据合成引擎与十万级并发的交互沙盒，将训练范式从传统的“静态轨迹模仿”转变为高效的“经验进化学习”。', '美团技术团队推出了 EvoCUA 模型并在 Github、Huggingface 开源，通过构建可验证数据合成引擎与十万级并发的交互沙盒，将训练范式从传统的“静态轨迹模仿”转变为高效的“经验进化学习”。', 6, '美团技术团队', 'https://tech.meituan.com/2026/01/26/evocua.html', '美团技术团队', 'blog', '["\u540e\u7aef", "\u6280\u672f", "\u67b6\u6784"]', '2026-01-26 00:00:00.000000', '2026-04-07 04:26:49.832481', 'https://tech.meituan.com/2026/01/26/evocua.html', 0.0, 0);
