INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (40, 'KuiTest：基于大模型通识的 UI 交互遍历测试', '美团质效技术部联合复旦大学周扬帆教授团队推出 KuiTest——零规则 UI 功能性异常测试工具。KuiTest 通过将“人类预期”直接用作 Test Oracle，解决了长期以来 UI 测试 Oracle 泛化性差的自动化痛点。实验表明，KuiTest 异常召回率达 86%，误报率仅 1.2%，已在执行 21 万+测试用例，发现百余例有效缺陷，大幅降低人工成本并提升测试覆盖率。', '美团质效技术部联合复旦大学周扬帆教授团队推出 KuiTest——零规则 UI 功能性异常测试工具。KuiTest 通过将“人类预期”直接用作 Test Oracle，解决了长期以来 UI 测试 Oracle 泛化性差的自动化痛点。实验表明，KuiTest 异常召回率达 86%，误报率仅 1.2%，已在执行 21 万+测试用例，发现百余例有效缺陷，大幅降低人工成本并提升测试覆盖率。', 6, '美团技术团队', 'https://tech.meituan.com/2026/01/13/kuitest-ui.html', '美团技术团队', 'blog', '["\u540e\u7aef", "\u6280\u672f", "\u67b6\u6784"]', '2026-01-13 00:00:00.000000', '2026-04-07 04:26:49.832497', 'https://tech.meituan.com/2026/01/13/kuitest-ui.html', 0.0, 0);
