INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (99, '探访帝国之心，吴哥旅行完全指南（上） ：行程设计', '2026 年的第一场旅行，我把目的地交给了暹粒，突然理解了为什么法国人会说「即使是古希腊和古罗马遗迹，在吴哥窟面前也要黯然失色。」查看全文', '2026 年的第一场旅行，我把目的地交给了暹粒，突然理解了为什么法国人会说「即使是古希腊和古罗马遗迹，在吴哥窟面前也要黯然失色。」<a href="https://sspai.com/post/106816" target="_blank">查看全文</a>', 9, '少数派', 'https://sspai.com/post/106816', '鸿苓', 'industry', '["\u6548\u7387", "\u5de5\u5177", "\u6570\u7801"]', '2026-03-13 08:00:00.000000', '2026-03-16 06:50:55.854296', 'https://sspai.com/post/106816', 0.0, 0);
