INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (345, 'Update to GPT-5 System Card: GPT-5.2', 'GPT-5.2 is the latest model family in the GPT-5 series. The comprehensive safety mitigation approach for these models is largely the same as that described in the GPT-5 System Card and GPT-5.1 System Card. Like OpenAI’s other models, the GPT-5.2 models were trained on diverse datasets, including information that is publicly available on the internet, information that we partner with third parties to access, and information that our users or human trainers and researchers provide or generate.', 'GPT-5.2 is the latest model family in the GPT-5 series. The comprehensive safety mitigation approach for these models is largely the same as that described in the GPT-5 System Card and GPT-5.1 System Card. Like OpenAI’s other models, the GPT-5.2 models were trained on diverse datasets, including information that is publicly available on the internet, information that we partner with third parties to access, and information that our users or human trainers and researchers provide or generate.', 14, 'OpenAI Blog', 'https://openai.com/index/gpt-5-system-card-update-gpt-5-2', '', 'ai_tech', '["OpenAI", "AI", "Publication", "GPT"]', '2025-12-11 00:00:00.000000', '2026-04-07 06:56:48.305042', 'https://openai.com/index/gpt-5-system-card-update-gpt-5-2', 0.0, 0);
