INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (807, 'Video generation models as world simulators', 'We explore large-scale training of generative models on video data. Specifically, we train text-conditional diffusion models jointly on videos and images of variable durations, resolutions and aspect ratios. We leverage a transformer architecture that operates on spacetime patches of video and image latent codes. Our largest model, Sora, is capable of generating a minute of high fidelity video. Our results suggest that scaling video generation models is a promising path towards building general ', 'We explore large-scale training of generative models on video data. Specifically, we train text-conditional diffusion models jointly on videos and images of variable durations, resolutions and aspect ratios. We leverage a transformer architecture that operates on spacetime patches of video and image latent codes. Our largest model, Sora, is capable of generating a minute of high fidelity video. Our results suggest that scaling video generation models is a promising path towards building general purpose simulators of the physical world.', 14, 'OpenAI Blog', 'https://openai.com/index/video-generation-models-as-world-simulators', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2024-02-15 08:00:00.000000', '2026-04-07 06:56:48.310011', 'https://openai.com/index/video-generation-models-as-world-simulators', 0.0, 0);
