INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (868, 'Language models can explain neurons in language models', 'We use GPT-4 to automatically write explanations for the behavior of neurons in large language models and to score those explanations. We release a dataset of these (imperfect) explanations and scores for every neuron in GPT-2.', 'We use GPT-4 to automatically write explanations for the behavior of neurons in large language models and to score those explanations. We release a dataset of these (imperfect) explanations and scores for every neuron in GPT-2.', 14, 'OpenAI Blog', 'https://openai.com/index/language-models-can-explain-neurons-in-language-models', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2023-05-09 07:00:00.000000', '2026-04-07 06:56:48.310621', 'https://openai.com/index/language-models-can-explain-neurons-in-language-models', 0.0, 0);
