INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (873, 'ChatGPT plugins', 'We’ve implemented initial support for plugins in ChatGPT. Plugins are tools designed specifically for language models with safety as a core principle, and help ChatGPT access up-to-date information, run computations, or use third-party services.', 'We’ve implemented initial support for plugins in ChatGPT. Plugins are tools designed specifically for language models with safety as a core principle, and help ChatGPT access up-to-date information, run computations, or use third-party services.', 14, 'OpenAI Blog', 'https://openai.com/index/chatgpt-plugins', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Product"]', '2023-03-23 07:00:00.000000', '2026-04-07 06:56:48.310670', 'https://openai.com/index/chatgpt-plugins', 0.0, 0);
