INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (879, 'GPT-4', 'We’ve created GPT-4, the latest milestone in OpenAI’s effort in scaling up deep learning. GPT-4 is a large multimodal model (accepting image and text inputs, emitting text outputs) that, while less capable than humans in many real-world scenarios, exhibits human-level performance on various professional and academic benchmarks.', 'We’ve created GPT-4, the latest milestone in OpenAI’s effort in scaling up deep learning. GPT-4 is a large multimodal model (accepting image and text inputs, emitting text outputs) that, while less capable than humans in many real-world scenarios, exhibits human-level performance on various professional and academic benchmarks.', 14, 'OpenAI Blog', 'https://openai.com/index/gpt-4-research', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2023-03-14 07:00:00.000000', '2026-04-07 06:56:48.310700', 'https://openai.com/index/gpt-4-research', 0.0, 0);
