INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (882, 'How should AI systems behave, and who should decide?', 'We’re clarifying how ChatGPT’s behavior is shaped and our plans for improving that behavior, allowing more user customization, and getting more public input into our decision-making in these areas.', 'We’re clarifying how ChatGPT’s behavior is shaped and our plans for improving that behavior, allowing more user customization, and getting more public input into our decision-making in these areas.', 14, 'OpenAI Blog', 'https://openai.com/index/how-should-ai-systems-behave', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2023-02-16 08:00:00.000000', '2026-04-07 06:56:48.310761', 'https://openai.com/index/how-should-ai-systems-behave', 0.0, 0);
