INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (931, 'Solving math word problems', 'We’ve trained a system that solves grade school math problems with nearly twice the accuracy of a fine-tuned GPT-3 model. It solves about 90% as many problems as real kids: a small sample of 9-12 year olds scored 60% on a test from our dataset, while our system scored 55% on those same problems.', 'We’ve trained a system that solves grade school math problems with nearly twice the accuracy of a fine-tuned GPT-3 model. It solves about 90% as many problems as real kids: a small sample of 9-12 year olds scored 60% on a test from our dataset, while our system scored 55% on those same problems.', 14, 'OpenAI Blog', 'https://openai.com/index/solving-math-word-problems', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2021-10-29 07:00:00.000000', '2026-04-07 06:56:48.311249', 'https://openai.com/index/solving-math-word-problems', 0.0, 0);
