INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (935, 'OpenAI Codex', 'We’ve created an improved version of OpenAI Codex, our AI system that translates natural language to code, and we are releasing it through our API in private beta starting today.', 'We’ve created an improved version of OpenAI Codex, our AI system that translates natural language to code, and we are releasing it through our API in private beta starting today.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-codex', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Product"]', '2021-08-10 07:00:00.000000', '2026-04-07 06:56:48.311288', 'https://openai.com/index/openai-codex', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (936, 'Introducing Triton: Open-source GPU programming for neural networks', 'We’re releasing Triton 1.0, an open-source Python-like programming language which enables researchers with no CUDA experience to write highly efficient GPU code—most of the time on par with what an expert would be able to produce.', 'We’re releasing Triton 1.0, an open-source Python-like programming language which enables researchers with no CUDA experience to write highly efficient GPU code—most of the time on par with what an expert would be able to produce.', 14, 'OpenAI Blog', 'https://openai.com/index/triton', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2021-07-28 07:00:00.000000', '2026-04-07 06:56:48.311298', 'https://openai.com/index/triton', 0.0, 0);
