INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (938, 'Improving language model behavior by training on a curated dataset', 'Our latest research finds we can improve language model behavior with respect to specific behavioral values by fine-tuning on a small, curated dataset.', 'Our latest research finds we can improve language model behavior with respect to specific behavioral values by fine-tuning on a small, curated dataset.', 14, 'OpenAI Blog', 'https://openai.com/index/improving-language-model-behavior', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2021-06-10 07:00:00.000000', '2026-04-07 06:56:48.311317', 'https://openai.com/index/improving-language-model-behavior', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (939, 'OpenAI Scholars 2021: Final projects', 'We’re proud to announce that the 2021 class of OpenAI Scholars has completed our six-month mentorship program and have produced an open-source research project with stipends and support from OpenAI.', 'We’re proud to announce that the 2021 class of OpenAI Scholars has completed our six-month mentorship program and have produced an open-source research project with stipends and support from OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2021-final-projects', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2021-05-10 07:00:00.000000', '2026-04-07 06:56:48.311327', 'https://openai.com/index/openai-scholars-2021-final-projects', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (940, 'Will Hurd joins OpenAI’s board of directors', 'OpenAI is committed to developing general-purpose artificial intelligence that benefits all humanity, and we believe that achieving our goal requires expertise in public policy as well as technology. So, we’re delighted to announce that Congressman Will Hurd has joined our board of directors.', 'OpenAI is committed to developing general-purpose artificial intelligence that benefits all humanity, and we believe that achieving our goal requires expertise in public policy as well as technology. So, we’re delighted to announce that Congressman Will Hurd has joined our board of directors.', 14, 'OpenAI Blog', 'https://openai.com/index/will-hurd-joins', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2021-05-03 07:00:00.000000', '2026-04-07 06:56:48.311338', 'https://openai.com/index/will-hurd-joins', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (941, 'GPT-3 powers the next generation of apps', 'Over 300 applications are delivering GPT-3–powered search, conversation, text completion, and other advanced AI features through our API.', 'Over 300 applications are delivering GPT-3–powered search, conversation, text completion, and other advanced AI features through our API.', 14, 'OpenAI Blog', 'https://openai.com/index/gpt-3-apps', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Product"]', '2021-03-25 07:00:00.000000', '2026-04-07 06:56:48.311348', 'https://openai.com/index/gpt-3-apps', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (942, 'Multimodal neurons in artificial neural networks', 'We’ve discovered neurons in CLIP that respond to the same concept whether presented literally, symbolically, or conceptually. This may explain CLIP’s accuracy in classifying surprising visual renditions of concepts, and is also an important step toward understanding the associations and biases that CLIP and similar models learn.', 'We’ve discovered neurons in CLIP that respond to the same concept whether presented literally, symbolically, or conceptually. This may explain CLIP’s accuracy in classifying surprising visual renditions of concepts, and is also an important step toward understanding the associations and biases that CLIP and similar models learn.', 14, 'OpenAI Blog', 'https://openai.com/index/multimodal-neurons', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2021-03-04 08:00:00.000000', '2026-04-07 06:56:48.311358', 'https://openai.com/index/multimodal-neurons', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (943, 'Understanding the capabilities, limitations, and societal impact of large language models', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/understanding-the-capabilities-limitations-and-societal-impact-of-large-language-models', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2021-02-04 08:00:00.000000', '2026-04-07 06:56:48.311367', 'https://openai.com/index/understanding-the-capabilities-limitations-and-societal-impact-of-large-language-models', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (944, 'Scaling Kubernetes to 7,500 nodes', 'We’ve scaled Kubernetes clusters to 7,500 nodes, producing a scalable infrastructure for large models like GPT-3, CLIP, and DALL·E, but also for rapid small-scale iterative research such as Scaling Laws for Neural Language Models.', 'We’ve scaled Kubernetes clusters to 7,500 nodes, producing a scalable infrastructure for large models like GPT-3, CLIP, and DALL·E, but also for rapid small-scale iterative research such as Scaling Laws for Neural Language Models.', 14, 'OpenAI Blog', 'https://openai.com/index/scaling-kubernetes-to-7500-nodes', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2021-01-25 08:00:00.000000', '2026-04-07 06:56:48.311377', 'https://openai.com/index/scaling-kubernetes-to-7500-nodes', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (945, 'CLIP: Connecting text and images', 'We’re introducing a neural network called CLIP which efficiently learns visual concepts from natural language supervision. CLIP can be applied to any visual classification benchmark by simply providing the names of the visual categories to be recognized, similar to the “zero-shot” capabilities of GPT-2 and GPT-3.', 'We’re introducing a neural network called CLIP which efficiently learns visual concepts from natural language supervision. CLIP can be applied to any visual classification benchmark by simply providing the names of the visual categories to be recognized, similar to the “zero-shot” capabilities of GPT-2 and GPT-3.', 14, 'OpenAI Blog', 'https://openai.com/index/clip', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2021-01-05 08:00:00.000000', '2026-04-07 06:56:48.311397', 'https://openai.com/index/clip', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (946, 'DALL·E: Creating images from text', 'We’ve trained a neural network called DALL·E that creates images from text captions for a wide range of concepts expressible in natural language.', 'We’ve trained a neural network called DALL·E that creates images from text captions for a wide range of concepts expressible in natural language.', 14, 'OpenAI Blog', 'https://openai.com/index/dall-e', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2021-01-05 08:00:00.000000', '2026-04-07 06:56:48.311387', 'https://openai.com/index/dall-e', 0.0, 0);
