INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (950, 'Learning to summarize with human feedback', 'We’ve applied reinforcement learning from human feedback to train language models that are better at summarization.', 'We’ve applied reinforcement learning from human feedback to train language models that are better at summarization.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-to-summarize-with-human-feedback', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2020-09-04 07:00:00.000000', '2026-04-07 06:56:48.311436', 'https://openai.com/index/learning-to-summarize-with-human-feedback', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (951, 'OpenAI Scholars 2020: Final projects', 'Our third class of OpenAI Scholars presented their final projects at virtual Demo Day, showcasing their research results from over the past five months.', 'Our third class of OpenAI Scholars presented their final projects at virtual Demo Day, showcasing their research results from over the past five months.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2020-final-projects', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2020-07-09 07:00:00.000000', '2026-04-07 06:56:48.311445', 'https://openai.com/index/openai-scholars-2020-final-projects', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (952, 'Procgen and MineRL Competitions', 'We’re excited to announce that OpenAI is co-organizing two NeurIPS 2020 competitions with AIcrowd, Carnegie Mellon University, and DeepMind, using Procgen Benchmark and MineRL.', 'We’re excited to announce that OpenAI is co-organizing two NeurIPS 2020 competitions with AIcrowd, Carnegie Mellon University, and DeepMind, using Procgen Benchmark and MineRL.', 14, 'OpenAI Blog', 'https://openai.com/index/procgen-minerl-competitions', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2020-06-20 07:00:00.000000', '2026-04-07 06:56:48.311455', 'https://openai.com/index/procgen-minerl-competitions', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (953, 'Image GPT', 'We find that, just as a large transformer model trained on language can generate coherent text, the same exact model trained on pixel sequences can generate coherent image completions and samples. By establishing a correlation between sample quality and image classification accuracy, we show that our best generative model also contains features competitive with top convolutional nets in the unsupervised setting.', 'We find that, just as a large transformer model trained on language can generate coherent text, the same exact model trained on pixel sequences can generate coherent image completions and samples. By establishing a correlation between sample quality and image classification accuracy, we show that our best generative model also contains features competitive with top convolutional nets in the unsupervised setting.', 14, 'OpenAI Blog', 'https://openai.com/index/image-gpt', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2020-06-17 07:00:00.000000', '2026-04-07 06:56:48.311465', 'https://openai.com/index/image-gpt', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (954, 'OpenAI API', 'We’re releasing an API for accessing new AI models developed by OpenAI.', 'We’re releasing an API for accessing new AI models developed by OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-api', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Product"]', '2020-06-11 07:00:00.000000', '2026-04-07 06:56:48.311475', 'https://openai.com/index/openai-api', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (955, 'Language models are few-shot learners', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/language-models-are-few-shot-learners', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2020-05-28 07:00:00.000000', '2026-04-07 06:56:48.311484', 'https://openai.com/index/language-models-are-few-shot-learners', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (956, 'AI and efficiency', 'We’re releasing an analysis showing that since 2012 the amount of compute needed to train a neural net to the same performance on ImageNet classification has been decreasing by a factor of 2 every 16 months. Compared to 2012, it now takes 44 times less compute to train a neural network to the level of AlexNet (by contrast, Moore’s Law would yield an 11x cost improvement over this period). Our results suggest that for AI tasks with high levels of recent investment, algorithmic progress has yielde', 'We’re releasing an analysis showing that since 2012 the amount of compute needed to train a neural net to the same performance on ImageNet classification has been decreasing by a factor of 2 every 16 months. Compared to 2012, it now takes 44 times less compute to train a neural network to the level of AlexNet (by contrast, Moore’s Law would yield an 11x cost improvement over this period). Our results suggest that for AI tasks with high levels of recent investment, algorithmic progress has yielded more gains than classical hardware efficiency.', 14, 'OpenAI Blog', 'https://openai.com/index/ai-and-efficiency', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2020-05-05 07:00:00.000000', '2026-04-07 06:56:48.311496', 'https://openai.com/index/ai-and-efficiency', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (957, 'Jukebox', 'We’re introducing Jukebox, a neural net that generates music, including rudimentary singing, as raw audio in a variety of genres and artist styles. We’re releasing the model weights and code, along with a tool to explore the generated samples.', 'We’re introducing Jukebox, a neural net that generates music, including rudimentary singing, as raw audio in a variety of genres and artist styles. We’re releasing the model weights and code, along with a tool to explore the generated samples.', 14, 'OpenAI Blog', 'https://openai.com/index/jukebox', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2020-04-30 07:00:00.000000', '2026-04-07 06:56:48.311506', 'https://openai.com/index/jukebox', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (958, 'Improving verifiability in AI development', 'We’ve contributed to a multi-stakeholder report by 58 co-authors at 30 organizations, including the Centre for the Future of Intelligence, Mila, Schwartz Reisman Institute for Technology and Society, Center for Advanced Study in the Behavioral Sciences, and Center for Security and Emerging Technologies. This report describes 10 mechanisms to improve the verifiability of claims made about AI systems. Developers can use these tools to provide evidence that AI systems are safe, secure, fair, or pri', 'We’ve contributed to a multi-stakeholder report by 58 co-authors at 30 organizations, including the Centre for the Future of Intelligence, Mila, Schwartz Reisman Institute for Technology and Society, Center for Advanced Study in the Behavioral Sciences, and Center for Security and Emerging Technologies. This report describes 10 mechanisms to improve the verifiability of claims made about AI systems. Developers can use these tools to provide evidence that AI systems are safe, secure, fair, or privacy-preserving. Users, policymakers, and civil society can use these tools to evaluate AI development processes.', 14, 'OpenAI Blog', 'https://openai.com/index/improving-verifiability', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2020-04-16 07:00:00.000000', '2026-04-07 06:56:48.311517', 'https://openai.com/index/improving-verifiability', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (959, 'OpenAI Microscope', 'We’re introducing OpenAI Microscope, a collection of visualizations of every significant layer and neuron of eight vision “model organisms” which are often studied in interpretability. Microscope makes it easier to analyze the features that form inside these neural networks, and we hope it will help the research community as we move towards understanding these complicated systems.', 'We’re introducing OpenAI Microscope, a collection of visualizations of every significant layer and neuron of eight vision “model organisms” which are often studied in interpretability. Microscope makes it easier to analyze the features that form inside these neural networks, and we hope it will help the research community as we move towards understanding these complicated systems.', 14, 'OpenAI Blog', 'https://openai.com/index/microscope', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2020-04-14 07:00:00.000000', '2026-04-07 06:56:48.311534', 'https://openai.com/index/microscope', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (960, 'OpenAI standardizes on PyTorch', 'We are standardizing OpenAI’s deep learning framework on PyTorch.', 'We are standardizing OpenAI’s deep learning framework on PyTorch.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-pytorch', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2020-01-30 08:00:00.000000', '2026-04-07 06:56:48.311544', 'https://openai.com/index/openai-pytorch', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (961, 'Scaling laws for neural language models', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/scaling-laws-for-neural-language-models', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2020-01-23 08:00:00.000000', '2026-04-07 06:56:48.311554', 'https://openai.com/index/scaling-laws-for-neural-language-models', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (962, 'Dota 2 with large scale deep reinforcement learning', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/dota-2-with-large-scale-deep-reinforcement-learning', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-12-13 08:00:00.000000', '2026-04-07 06:56:48.311565', 'https://openai.com/index/dota-2-with-large-scale-deep-reinforcement-learning', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (963, 'Deep double descent', 'We show that the double descent phenomenon occurs in CNNs, ResNets, and transformers: performance first improves, then gets worse, and then improves again with increasing model size, data size, or training time. This effect is often avoided through careful regularization. While this behavior appears to be fairly universal, we don’t yet fully understand why it happens, and view further study of this phenomenon as an important research direction.', 'We show that the double descent phenomenon occurs in CNNs, ResNets, and transformers: performance first improves, then gets worse, and then improves again with increasing model size, data size, or training time. This effect is often avoided through careful regularization. While this behavior appears to be fairly universal, we don’t yet fully understand why it happens, and view further study of this phenomenon as an important research direction.', 14, 'OpenAI Blog', 'https://openai.com/index/deep-double-descent', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-12-05 08:00:00.000000', '2026-04-07 06:56:48.311575', 'https://openai.com/index/deep-double-descent', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (964, 'Procgen Benchmark', 'We’re releasing Procgen Benchmark, 16 simple-to-use procedurally-generated environments which provide a direct measure of how quickly a reinforcement learning agent learns generalizable skills.', 'We’re releasing Procgen Benchmark, 16 simple-to-use procedurally-generated environments which provide a direct measure of how quickly a reinforcement learning agent learns generalizable skills.', 14, 'OpenAI Blog', 'https://openai.com/index/procgen-benchmark', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-12-03 08:00:00.000000', '2026-04-07 06:56:48.311585', 'https://openai.com/index/procgen-benchmark', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (965, 'Benchmarking safe exploration in deep reinforcement learning', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/benchmarking-safe-exploration-in-deep-reinforcement-learning', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-11-21 08:00:00.000000', '2026-04-07 06:56:48.311604', 'https://openai.com/index/benchmarking-safe-exploration-in-deep-reinforcement-learning', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (966, 'Safety Gym', 'We’re releasing Safety Gym, a suite of environments and tools for measuring progress towards reinforcement learning agents that respect safety constraints while training.', 'We’re releasing Safety Gym, a suite of environments and tools for measuring progress towards reinforcement learning agents that respect safety constraints while training.', 14, 'OpenAI Blog', 'https://openai.com/index/safety-gym', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-11-21 08:00:00.000000', '2026-04-07 06:56:48.311595', 'https://openai.com/index/safety-gym', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (967, 'GPT-2: 1.5B release', 'As the final model release of GPT-2’s staged release, we’re releasing the largest version (1.5B parameters) of GPT-2 along with code and model weights to facilitate detection of outputs of GPT-2 models. While there have been larger language models released since August, we’ve continued with our original staged release plan in order to provide the community with a test case of a full staged release process. We hope that this test case will be useful to developers of future powerful models, and we', 'As the final model release of GPT-2’s staged release, we’re releasing the largest version (1.5B parameters) of GPT-2 along with code and model weights to facilitate detection of outputs of GPT-2 models. While there have been larger language models released since August, we’ve continued with our original staged release plan in order to provide the community with a test case of a full staged release process. We hope that this test case will be useful to developers of future powerful models, and we’re actively continuing the conversation with the AI community on responsible publication.', 14, 'OpenAI Blog', 'https://openai.com/index/gpt-2-1-5b-release', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-11-05 08:00:00.000000', '2026-04-07 06:56:48.311615', 'https://openai.com/index/gpt-2-1-5b-release', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (968, 'Solving Rubik’s Cube with a robot hand', 'We’ve trained a pair of neural networks to solve the Rubik’s Cube with a human-like robot hand. The neural networks are trained entirely in simulation, using the same reinforcement learning code as OpenAI Five paired with a new technique called Automatic Domain Randomization (ADR). The system can handle situations it never saw during training, such as being prodded by a stuffed giraffe. This shows that reinforcement learning isn’t just a tool for virtual tasks, but can solve physical-world probl', 'We’ve trained a pair of neural networks to solve the Rubik’s Cube with a human-like robot hand. The neural networks are trained entirely in simulation, using the same reinforcement learning code as OpenAI Five paired with a new technique called Automatic Domain Randomization (ADR). The system can handle situations it never saw during training, such as being prodded by a stuffed giraffe. This shows that reinforcement learning isn’t just a tool for virtual tasks, but can solve physical-world problems requiring unprecedented dexterity.', 14, 'OpenAI Blog', 'https://openai.com/index/solving-rubiks-cube', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-10-15 07:00:00.000000', '2026-04-07 06:56:48.311625', 'https://openai.com/index/solving-rubiks-cube', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (969, 'OpenAI Scholars 2020: Applications open', 'We are now accepting applications for our third class of OpenAI Scholars.', 'We are now accepting applications for our third class of OpenAI Scholars.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2020', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-10-11 07:00:00.000000', '2026-04-07 06:56:48.311636', 'https://openai.com/index/openai-scholars-2020', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (970, 'Fine-tuning GPT-2 from human preferences', 'We’ve fine-tuned the 774M parameter GPT-2 language model using human feedback for various tasks, successfully matching the preferences of the external human labelers, though those preferences did not always match our own. Specifically, for summarization tasks the labelers preferred sentences copied wholesale from the input (we’d only asked them to ensure accuracy), so our models learned to copy. Summarization required 60k human labels; simpler tasks which continue text in various styles required', 'We’ve fine-tuned the 774M parameter GPT-2 language model using human feedback for various tasks, successfully matching the preferences of the external human labelers, though those preferences did not always match our own. Specifically, for summarization tasks the labelers preferred sentences copied wholesale from the input (we’d only asked them to ensure accuracy), so our models learned to copy. Summarization required 60k human labels; simpler tasks which continue text in various styles required only 5k. Our motivation is to move safety techniques closer to the general task of “machines talking to humans,” which we believe is key to extracting information about human values.', 14, 'OpenAI Blog', 'https://openai.com/index/fine-tuning-gpt-2', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-09-19 07:00:00.000000', '2026-04-07 06:56:48.311647', 'https://openai.com/index/fine-tuning-gpt-2', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (971, 'Emergent tool use from multi-agent interaction', 'We’ve observed agents discovering progressively more complex tool use while playing a simple game of hide-and-seek. Through training in our new simulated hide-and-seek environment, agents build a series of six distinct strategies and counterstrategies, some of which we did not know our environment supported. The self-supervised emergent complexity in this simple environment further suggests that multi-agent co-adaptation may one day produce extremely complex and intelligent behavior.', 'We’ve observed agents discovering progressively more complex tool use while playing a simple game of hide-and-seek. Through training in our new simulated hide-and-seek environment, agents build a series of six distinct strategies and counterstrategies, some of which we did not know our environment supported. The self-supervised emergent complexity in this simple environment further suggests that multi-agent co-adaptation may one day produce extremely complex and intelligent behavior.', 14, 'OpenAI Blog', 'https://openai.com/index/emergent-tool-use', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-09-17 07:00:00.000000', '2026-04-07 06:56:48.311657', 'https://openai.com/index/emergent-tool-use', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (972, 'Testing robustness against unforeseen adversaries', 'We’ve developed a method to assess whether a neural network classifier can reliably defend against adversarial attacks not seen during training. Our method yields a new metric, UAR (Unforeseen Attack Robustness), which evaluates the robustness of a single model against an unanticipated attack, and highlights the need to measure performance across a more diverse range of unforeseen attacks.', 'We’ve developed a method to assess whether a neural network classifier can reliably defend against adversarial attacks not seen during training. Our method yields a new metric, UAR (Unforeseen Attack Robustness), which evaluates the robustness of a single model against an unanticipated attack, and highlights the need to measure performance across a more diverse range of unforeseen attacks.', 14, 'OpenAI Blog', 'https://openai.com/index/testing-robustness', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-08-22 07:00:00.000000', '2026-04-07 06:56:48.311667', 'https://openai.com/index/testing-robustness', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (973, 'GPT-2: 6-month follow-up', 'We’re releasing the 774 million parameter GPT-2 language model after the release of our small 124M model in February, staged release of our medium 355M model in May, and subsequent research with partners and the AI community into the model’s potential for misuse and societal benefit. We’re also releasing an open-source legal agreement to make it easier for organizations to initiate model-sharing partnerships with each other, and are publishing a technical report about our experience in coordinat', 'We’re releasing the 774 million parameter GPT-2 language model after the release of our small 124M model in February, staged release of our medium 355M model in May, and subsequent research with partners and the AI community into the model’s potential for misuse and societal benefit. We’re also releasing an open-source legal agreement to make it easier for organizations to initiate model-sharing partnerships with each other, and are publishing a technical report about our experience in coordinating with the wider AI research community on publication norms.', 14, 'OpenAI Blog', 'https://openai.com/index/gpt-2-6-month-follow-up', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-08-20 07:00:00.000000', '2026-04-07 06:56:48.311677', 'https://openai.com/index/gpt-2-6-month-follow-up', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (974, 'Learning Day', 'At OpenAI, each Thursday is Learning Day: a day where employees have the option to self-study technical skills that will make them better at their job but which aren’t being learned from daily work.', 'At OpenAI, each Thursday is Learning Day: a day where employees have the option to self-study technical skills that will make them better at their job but which aren’t being learned from daily work.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-day', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-08-01 07:00:00.000000', '2026-04-07 06:56:48.311686', 'https://openai.com/index/learning-day', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (975, 'Microsoft invests in and partners with OpenAI to support us building beneficial AGI', 'Microsoft is investing $1 billion in OpenAI to support us building artificial general intelligence (AGI) with widely distributed economic benefits. We’re partnering to develop a hardware and software platform within Microsoft Azure which will scale to AGI. We’ll jointly develop new Azure AI supercomputing technologies, and Microsoft will become our exclusive cloud provider—so we’ll be working hard together to further extend Microsoft Azure’s capabilities in large-scale AI systems.', 'Microsoft is investing $1 billion in OpenAI to support us building artificial general intelligence (AGI) with widely distributed economic benefits. We’re partnering to develop a hardware and software platform within Microsoft Azure which will scale to AGI. We’ll jointly develop new Azure AI supercomputing technologies, and Microsoft will become our exclusive cloud provider—so we’ll be working hard together to further extend Microsoft Azure’s capabilities in large-scale AI systems.', 14, 'OpenAI Blog', 'https://openai.com/index/microsoft-invests-in-and-partners-with-openai', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-07-22 07:00:00.000000', '2026-04-07 06:56:48.311697', 'https://openai.com/index/microsoft-invests-in-and-partners-with-openai', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (976, 'Why responsible AI development needs cooperation on safety', 'We’ve written a policy research paper identifying four strategies that can be used today to improve the likelihood of long-term industry cooperation on safety norms in AI: communicating risks and benefits, technical collaboration, increased transparency, and incentivizing standards. Our analysis shows that industry cooperation on safety will be instrumental in ensuring that AI systems are safe and beneficial, but competitive pressures could lead to a collective action problem, potentially causin', 'We’ve written a policy research paper identifying four strategies that can be used today to improve the likelihood of long-term industry cooperation on safety norms in AI: communicating risks and benefits, technical collaboration, increased transparency, and incentivizing standards. Our analysis shows that industry cooperation on safety will be instrumental in ensuring that AI systems are safe and beneficial, but competitive pressures could lead to a collective action problem, potentially causing AI companies to under-invest in safety. We hope these strategies will encourage greater cooperation on the safe development of AI and lead to better global outcomes of AI.', 14, 'OpenAI Blog', 'https://openai.com/index/cooperation-on-safety', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-07-10 07:00:00.000000', '2026-04-07 06:56:48.311707', 'https://openai.com/index/cooperation-on-safety', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (977, 'OpenAI Robotics Symposium 2019', 'We hosted the first OpenAI Robotics Symposium on April 27, 2019.', 'We hosted the first OpenAI Robotics Symposium on April 27, 2019.', 14, 'OpenAI Blog', 'https://openai.com/index/symposium-2019', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-06-05 07:00:00.000000', '2026-04-07 06:56:48.311717', 'https://openai.com/index/symposium-2019', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (978, 'OpenAI Scholars 2019: Final projects', 'Our second class of OpenAI Scholars has concluded, with all eight scholars producing an exciting final project showcased at Scholars Demo Day at OpenAI.', 'Our second class of OpenAI Scholars has concluded, with all eight scholars producing an exciting final project showcased at Scholars Demo Day at OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2019-final-projects', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-05-23 07:00:00.000000', '2026-04-07 06:56:48.311726', 'https://openai.com/index/openai-scholars-2019-final-projects', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (979, 'OpenAI Fellows Fall 2018: Final projects', 'Our second class of OpenAI Fellows has wrapped up, with each Fellow going from a machine learning beginner to core OpenAI contributor in the course of a 6-month apprenticeship. We are currently reviewing applications on a rolling basis for our next round of OpenAI Fellows Summer 2019.', 'Our second class of OpenAI Fellows has wrapped up, with each Fellow going from a machine learning beginner to core OpenAI contributor in the course of a 6-month apprenticeship. We are currently reviewing applications on a rolling basis for our next round of OpenAI Fellows Summer 2019.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-fellows-fall-2018', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-05-17 07:00:00.000000', '2026-04-07 06:56:48.311736', 'https://openai.com/index/openai-fellows-fall-2018', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (980, 'Transfer of adversarial robustness between perturbation types', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/transfer-of-adversarial-robustness-between-perturbation-types', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-05-03 07:00:00.000000', '2026-04-07 06:56:48.311746', 'https://openai.com/index/transfer-of-adversarial-robustness-between-perturbation-types', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (981, 'MuseNet', 'We’ve created MuseNet, a deep neural network that can generate 4-minute musical compositions with 10 different instruments, and can combine styles from country to Mozart to the Beatles. MuseNet was not explicitly programmed with our understanding of music, but instead discovered patterns of harmony, rhythm, and style by learning to predict the next token in hundreds of thousands of MIDI files. MuseNet uses the same general-purpose unsupervised technology as GPT-2, a large-scale transformer model', 'We’ve created MuseNet, a deep neural network that can generate 4-minute musical compositions with 10 different instruments, and can combine styles from country to Mozart to the Beatles. MuseNet was not explicitly programmed with our understanding of music, but instead discovered patterns of harmony, rhythm, and style by learning to predict the next token in hundreds of thousands of MIDI files. MuseNet uses the same general-purpose unsupervised technology as GPT-2, a large-scale transformer model trained to predict the next token in a sequence, whether audio or text.', 14, 'OpenAI Blog', 'https://openai.com/index/musenet', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-04-25 07:00:00.000000', '2026-04-07 06:56:48.311756', 'https://openai.com/index/musenet', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (982, 'Generative modeling with sparse transformers', 'We’ve developed the Sparse Transformer, a deep neural network which sets new records at predicting what comes next in a sequence—whether text, images, or sound. It uses an algorithmic improvement of the attention mechanism to extract patterns from sequences 30x longer than possible previously.', 'We’ve developed the Sparse Transformer, a deep neural network which sets new records at predicting what comes next in a sequence—whether text, images, or sound. It uses an algorithmic improvement of the attention mechanism to extract patterns from sequences 30x longer than possible previously.', 14, 'OpenAI Blog', 'https://openai.com/index/sparse-transformer', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-04-23 07:00:00.000000', '2026-04-07 06:56:48.311766', 'https://openai.com/index/sparse-transformer', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (983, 'OpenAI Five defeats Dota 2 world champions', 'OpenAI Five is the first AI to beat the world champions in an esports game, having won two back-to-back games versus the world champion Dota 2 team, OG, at Finals this weekend. Both OpenAI Five and DeepMind’s AlphaStar had previously beaten good pros privately but lost their live pro matches, making this also the first time an AI has beaten esports pros on livestream.', 'OpenAI Five is the first AI to beat the world champions in an esports game, having won two back-to-back games versus the world champion Dota 2 team, OG, at Finals this weekend. Both OpenAI Five and DeepMind’s AlphaStar had previously beaten good pros privately but lost their live pro matches, making this also the first time an AI has beaten esports pros on livestream.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-five-defeats-dota-2-world-champions', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-04-15 07:00:00.000000', '2026-04-07 06:56:48.311776', 'https://openai.com/index/openai-five-defeats-dota-2-world-champions', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (984, 'OpenAI Five Finals', 'We’ll be holding our final live event for OpenAI Five at 11:30am PT on April 13.', 'We’ll be holding our final live event for OpenAI Five at 11:30am PT on April 13.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-five-finals', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-03-26 07:00:00.000000', '2026-04-07 06:56:48.311786', 'https://openai.com/index/openai-five-finals', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (985, 'Implicit generation and generalization methods for energy-based models', 'We’ve made progress towards stable and scalable training of energy-based models (EBMs) resulting in better sample quality and generalization ability than existing models. Generation in EBMs spends more compute to continually refine its answers and doing so can generate samples competitive with GANs at low temperatures, while also having mode coverage guarantees of likelihood-based models. We hope these findings stimulate further research into this promising class of models.', 'We’ve made progress towards stable and scalable training of energy-based models (EBMs) resulting in better sample quality and generalization ability than existing models. Generation in EBMs spends more compute to continually refine its answers and doing so can generate samples competitive with GANs at low temperatures, while also having mode coverage guarantees of likelihood-based models. We hope these findings stimulate further research into this promising class of models.', 14, 'OpenAI Blog', 'https://openai.com/index/energy-based-models', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-03-21 07:00:00.000000', '2026-04-07 06:56:48.311796', 'https://openai.com/index/energy-based-models', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (986, 'OpenAI Scholars 2019: Meet our Scholars', 'Our class of eight scholars (out of 550 applicants) brings together collective expertise in literature, philosophy, cell biology, statistics, economics, quantum physics, and business innovation.', 'Our class of eight scholars (out of 550 applicants) brings together collective expertise in literature, philosophy, cell biology, statistics, economics, quantum physics, and business innovation.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2019-meet-our-scholars', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-03-13 07:00:00.000000', '2026-04-07 06:56:48.311805', 'https://openai.com/index/openai-scholars-2019-meet-our-scholars', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (987, 'OpenAI LP', 'We’ve created OpenAI LP, a new “capped-profit” company that allows us to rapidly increase our investments in compute and talent while including checks and balances to actualize our mission.', 'We’ve created OpenAI LP, a new “capped-profit” company that allows us to rapidly increase our investments in compute and talent while including checks and balances to actualize our mission.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-lp', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-03-11 07:00:00.000000', '2026-04-07 06:56:48.311815', 'https://openai.com/index/openai-lp', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (988, 'Introducing Activation Atlases', 'We’ve created activation atlases (in collaboration with Google researchers), a new technique for visualizing what interactions between neurons can represent. As AI systems are deployed in increasingly sensitive contexts, having a better understanding of their internal decision-making processes will let us identify weaknesses and investigate failures.', 'We’ve created activation atlases (in collaboration with Google researchers), a new technique for visualizing what interactions between neurons can represent. As AI systems are deployed in increasingly sensitive contexts, having a better understanding of their internal decision-making processes will let us identify weaknesses and investigate failures.', 14, 'OpenAI Blog', 'https://openai.com/index/introducing-activation-atlases', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-03-06 08:00:00.000000', '2026-04-07 06:56:48.311825', 'https://openai.com/index/introducing-activation-atlases', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (989, 'Neural MMO: A massively multiagent game environment', 'We’re releasing a Neural MMO, a massively multiagent game environment for reinforcement learning agents. Our platform supports a large, variable number of agents within a persistent and open-ended task. The inclusion of many agents and species leads to better exploration, divergent niche formation, and greater overall competence.', 'We’re releasing a Neural MMO, a massively multiagent game environment for reinforcement learning agents. Our platform supports a large, variable number of agents within a persistent and open-ended task. The inclusion of many agents and species leads to better exploration, divergent niche formation, and greater overall competence.', 14, 'OpenAI Blog', 'https://openai.com/index/neural-mmo', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-03-04 08:00:00.000000', '2026-04-07 06:56:48.311835', 'https://openai.com/index/neural-mmo', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (990, 'Spinning Up in Deep RL: Workshop review', 'On February 2, we held our first Spinning Up Workshop as part of our new education initiative at OpenAI.', 'On February 2, we held our first Spinning Up Workshop as part of our new education initiative at OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/spinning-up-in-deep-rl-workshop-review', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2019-02-26 08:00:00.000000', '2026-04-07 06:56:48.311845', 'https://openai.com/index/spinning-up-in-deep-rl-workshop-review', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (991, 'AI safety needs social scientists', 'We’ve written a paper arguing that long-term AI safety research needs social scientists to ensure AI alignment algorithms succeed when actual humans are involved. Properly aligning advanced AI systems with human values requires resolving many uncertainties related to the psychology of human rationality, emotion, and biases. The aim of this paper is to spark further collaboration between machine learning and social science researchers, and we plan to hire social scientists to work on this full ti', 'We’ve written a paper arguing that long-term AI safety research needs social scientists to ensure AI alignment algorithms succeed when actual humans are involved. Properly aligning advanced AI systems with human values requires resolving many uncertainties related to the psychology of human rationality, emotion, and biases. The aim of this paper is to spark further collaboration between machine learning and social science researchers, and we plan to hire social scientists to work on this full time at OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/ai-safety-needs-social-scientists', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2019-02-19 08:00:00.000000', '2026-04-07 06:56:48.311855', 'https://openai.com/index/ai-safety-needs-social-scientists', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (992, 'Better language models and their implications', 'We’ve trained a large-scale unsupervised language model which generates coherent paragraphs of text, achieves state-of-the-art performance on many language modeling benchmarks, and performs rudimentary reading comprehension, machine translation, question answering, and summarization—all without task-specific training.', 'We’ve trained a large-scale unsupervised language model which generates coherent paragraphs of text, achieves state-of-the-art performance on many language modeling benchmarks, and performs rudimentary reading comprehension, machine translation, question answering, and summarization—all without task-specific training.', 14, 'OpenAI Blog', 'https://openai.com/index/better-language-models', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-02-14 08:00:00.000000', '2026-04-07 06:56:48.311865', 'https://openai.com/index/better-language-models', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (993, 'Computational limitations in robust classification and win-win results', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/computational-limitations-in-robust-classification-and-win-win-results', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2019-02-04 08:00:00.000000', '2026-04-07 06:56:48.311875', 'https://openai.com/index/computational-limitations-in-robust-classification-and-win-win-results', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (994, 'OpenAI Fellows Summer 2018: Final projects', 'Our first cohort of OpenAI Fellows has concluded, with each Fellow going from a machine learning beginner to core OpenAI contributor in the course of a 6-month apprenticeship.', 'Our first cohort of OpenAI Fellows has concluded, with each Fellow going from a machine learning beginner to core OpenAI contributor in the course of a 6-month apprenticeship.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-summer-fellows-2018', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-12-19 08:00:00.000000', '2026-04-07 06:56:48.311885', 'https://openai.com/index/openai-summer-fellows-2018', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (995, 'How AI training scales', 'We’ve discovered that the gradient noise scale, a simple statistical metric, predicts the parallelizability of neural network training on a wide range of tasks. Since complex tasks tend to have noisier gradients, increasingly large batch sizes are likely to become useful in the future, removing one potential limit to further growth of AI systems. More broadly, these results show that neural network training need not be considered a mysterious art, but can be rigorized and systematized.', 'We’ve discovered that the gradient noise scale, a simple statistical metric, predicts the parallelizability of neural network training on a wide range of tasks. Since complex tasks tend to have noisier gradients, increasingly large batch sizes are likely to become useful in the future, removing one potential limit to further growth of AI systems. More broadly, these results show that neural network training need not be considered a mysterious art, but can be rigorized and systematized.', 14, 'OpenAI Blog', 'https://openai.com/index/how-ai-training-scales', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-12-14 08:00:00.000000', '2026-04-07 06:56:48.311895', 'https://openai.com/index/how-ai-training-scales', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (996, 'Quantifying generalization in reinforcement learning', 'We’re releasing CoinRun, a training environment which provides a metric for an agent’s ability to transfer its experience to novel situations and has already helped clarify a longstanding puzzle in reinforcement learning. CoinRun strikes a desirable balance in complexity: the environment is simpler than traditional platformer games like Sonic the Hedgehog but still poses a worthy generalization challenge for state of the art algorithms.', 'We’re releasing CoinRun, a training environment which provides a metric for an agent’s ability to transfer its experience to novel situations and has already helped clarify a longstanding puzzle in reinforcement learning. CoinRun strikes a desirable balance in complexity: the environment is simpler than traditional platformer games like Sonic the Hedgehog but still poses a worthy generalization challenge for state of the art algorithms.', 14, 'OpenAI Blog', 'https://openai.com/index/quantifying-generalization-in-reinforcement-learning', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-12-06 08:00:00.000000', '2026-04-07 06:56:48.311905', 'https://openai.com/index/quantifying-generalization-in-reinforcement-learning', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (997, 'Spinning Up in Deep RL', 'We’re releasing Spinning Up in Deep RL, an educational resource designed to let anyone learn to become a skilled practitioner in deep reinforcement learning. Spinning Up consists of crystal-clear examples of RL code, educational exercises, documentation, and tutorials.', 'We’re releasing Spinning Up in Deep RL, an educational resource designed to let anyone learn to become a skilled practitioner in deep reinforcement learning. Spinning Up consists of crystal-clear examples of RL code, educational exercises, documentation, and tutorials.', 14, 'OpenAI Blog', 'https://openai.com/index/spinning-up-in-deep-rl', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-11-08 08:00:00.000000', '2026-04-07 06:56:48.311915', 'https://openai.com/index/spinning-up-in-deep-rl', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (998, 'Learning concepts with energy functions', 'We’ve developed an energy-based model that can quickly learn to identify and generate instances of concepts, such as near, above, between, closest, and furthest, expressed as sets of 2d points. Our model learns these concepts after only five demonstrations. We also show cross-domain transfer: we use concepts learned in a 2d particle environment to solve tasks on a 3-dimensional physics-based robot.', 'We’ve developed an energy-based model that can quickly learn to identify and generate instances of concepts, such as near, above, between, closest, and furthest, expressed as sets of 2d points. Our model learns these concepts after only five demonstrations. We also show cross-domain transfer: we use concepts learned in a 2d particle environment to solve tasks on a 3-dimensional physics-based robot.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-concepts-with-energy-functions', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-11-07 08:00:00.000000', '2026-04-07 06:56:48.311925', 'https://openai.com/index/learning-concepts-with-energy-functions', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (999, 'Plan online, learn offline: Efficient learning and exploration via model-based control', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/plan-online-learn-offline', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-11-05 08:00:00.000000', '2026-04-07 06:56:48.311935', 'https://openai.com/index/plan-online-learn-offline', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1000, 'Reinforcement learning with prediction-based rewards', 'We’ve developed Random Network Distillation (RND), a prediction-based method for encouraging reinforcement learning agents to explore their environments through curiosity, which for the first time exceeds average human performance on Montezuma’s Revenge.', 'We’ve developed Random Network Distillation (RND), a prediction-based method for encouraging reinforcement learning agents to explore their environments through curiosity, which for the first time exceeds average human performance on Montezuma’s Revenge.', 14, 'OpenAI Blog', 'https://openai.com/index/reinforcement-learning-with-prediction-based-rewards', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-10-31 07:00:00.000000', '2026-04-07 06:56:48.311944', 'https://openai.com/index/reinforcement-learning-with-prediction-based-rewards', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1001, 'Learning complex goals with iterated amplification', 'We’re proposing an AI safety technique called iterated amplification that lets us specify complicated behaviors and goals that are beyond human scale, by demonstrating how to decompose a task into simpler sub-tasks, rather than by providing labeled data or a reward function. Although this idea is in its very early stages and we have only completed experiments on simple toy algorithmic domains, we’ve decided to present it in its preliminary state because we think it could prove to be a scalable a', 'We’re proposing an AI safety technique called iterated amplification that lets us specify complicated behaviors and goals that are beyond human scale, by demonstrating how to decompose a task into simpler sub-tasks, rather than by providing labeled data or a reward function. Although this idea is in its very early stages and we have only completed experiments on simple toy algorithmic domains, we’ve decided to present it in its preliminary state because we think it could prove to be a scalable approach to AI safety.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-complex-goals-with-iterated-amplification', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2018-10-22 07:00:00.000000', '2026-04-07 06:56:48.311954', 'https://openai.com/index/learning-complex-goals-with-iterated-amplification', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1002, 'OpenAI Scholars 2019: Applications open', 'We are now accepting applications for our second cohort of OpenAI Scholars, a program where we provide 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 'We are now accepting applications for our second cohort of OpenAI Scholars, a program where we provide 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2019', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-10-11 07:00:00.000000', '2026-04-07 06:56:48.311964', 'https://openai.com/index/openai-scholars-2019', 0.0, 0);
