INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1011, 'OpenAI Scholars 2018: Meet our Scholars', 'Our first class of OpenAI Scholars is underway, and you can now follow along as this group of experienced software developers becomes machine learning practitioners.', 'Our first class of OpenAI Scholars is underway, and you can now follow along as this group of experienced software developers becomes machine learning practitioners.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2018-meet-our-scholars', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-07-25 07:00:00.000000', '2026-04-07 06:56:48.312051', 'https://openai.com/index/openai-scholars-2018-meet-our-scholars', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1012, 'OpenAI Five Benchmark', 'The OpenAI Five Benchmark match is now over!', 'The OpenAI Five Benchmark match is now over!', 14, 'OpenAI Blog', 'https://openai.com/index/openai-five-benchmark', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-07-18 07:00:00.000000', '2026-04-07 06:56:48.312061', 'https://openai.com/index/openai-five-benchmark', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1013, 'Glow: Better reversible generative models', 'We introduce Glow, a reversible generative model which uses invertible 1x1 convolutions. It extends previous work on reversible generative models and simplifies the architecture. Our model can generate realistic high resolution images, supports efficient sampling, and discovers features that can be used to manipulate attributes of data. We’re releasing code for the model and an online visualization tool so people can explore and build on these results.', 'We introduce Glow, a reversible generative model which uses invertible 1x1 convolutions. It extends previous work on reversible generative models and simplifies the architecture. Our model can generate realistic high resolution images, supports efficient sampling, and discovers features that can be used to manipulate attributes of data. We’re releasing code for the model and an online visualization tool so people can explore and build on these results.', 14, 'OpenAI Blog', 'https://openai.com/index/glow', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-07-09 07:00:00.000000', '2026-04-07 06:56:48.312071', 'https://openai.com/index/glow', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1014, 'Learning Montezuma’s Revenge from a single demonstration', 'We’ve trained an agent to achieve a high score of 74,500 on Montezuma’s Revenge from a single human demonstration, better than any previously published result. Our algorithm is simple: the agent plays a sequence of games starting from carefully chosen states from the demonstration, and learns from them by optimizing the game score using PPO, the same reinforcement learning algorithm that underpins OpenAI Five.', 'We’ve trained an agent to achieve a high score of 74,500 on Montezuma’s Revenge from a single human demonstration, better than any previously published result. Our algorithm is simple: the agent plays a sequence of games starting from carefully chosen states from the demonstration, and learns from them by optimizing the game score using PPO, the same reinforcement learning algorithm that underpins OpenAI Five.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-montezumas-revenge-from-a-single-demonstration', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-07-04 07:00:00.000000', '2026-04-07 06:56:48.312081', 'https://openai.com/index/learning-montezumas-revenge-from-a-single-demonstration', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1015, 'OpenAI Five', 'Our team of five neural networks, OpenAI Five, has started to defeat amateur human teams at Dota 2.', 'Our team of five neural networks, OpenAI Five, has started to defeat amateur human teams at Dota 2.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-five', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-06-25 07:00:00.000000', '2026-04-07 06:56:48.312090', 'https://openai.com/index/openai-five', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1016, 'Retro Contest: Results', 'The first run of our Retro Contest—exploring the development of algorithms that can generalize from previous experience—is now complete.', 'The first run of our Retro Contest—exploring the development of algorithms that can generalize from previous experience—is now complete.', 14, 'OpenAI Blog', 'https://openai.com/index/retro-contest-results', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-06-22 07:00:00.000000', '2026-04-07 06:56:48.312102', 'https://openai.com/index/retro-contest-results', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1017, 'Learning policy representations in multiagent systems', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/learning-policy-representations-in-multiagent-systems', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-06-17 07:00:00.000000', '2026-04-07 06:56:48.312112', 'https://openai.com/index/learning-policy-representations-in-multiagent-systems', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1018, 'Improving language understanding with unsupervised learning', 'We’ve obtained state-of-the-art results on a suite of diverse language tasks with a scalable, task-agnostic system, which we’re also releasing. Our approach is a combination of two existing ideas: transformers and unsupervised pre-training. These results provide a convincing example that pairing supervised learning methods with unsupervised pre-training works very well; this is an idea that many have explored in the past, and we hope our result motivates further research into applying this idea ', 'We’ve obtained state-of-the-art results on a suite of diverse language tasks with a scalable, task-agnostic system, which we’re also releasing. Our approach is a combination of two existing ideas: transformers and unsupervised pre-training. These results provide a convincing example that pairing supervised learning methods with unsupervised pre-training works very well; this is an idea that many have explored in the past, and we hope our result motivates further research into applying this idea on larger and more diverse datasets.', 14, 'OpenAI Blog', 'https://openai.com/index/language-unsupervised', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2018-06-11 07:00:00.000000', '2026-04-07 06:56:48.312122', 'https://openai.com/index/language-unsupervised', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1019, 'GamePad: A learning environment for theorem proving', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/gamepad', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-06-02 07:00:00.000000', '2026-04-07 06:56:48.312132', 'https://openai.com/index/gamepad', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1020, 'OpenAI Fellows Fall 2018', 'We’re now accepting applications for the next cohort of OpenAI Fellows, a program which offers a compensated 6-month apprenticeship in AI research at OpenAI.', 'We’re now accepting applications for the next cohort of OpenAI Fellows, a program which offers a compensated 6-month apprenticeship in AI research at OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-fellows', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2018-05-30 07:00:00.000000', '2026-04-07 06:56:48.312142', 'https://openai.com/index/openai-fellows', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1021, 'Gym Retro', 'We’re releasing the full version of Gym Retro, a platform for reinforcement learning research on games. This brings our publicly-released game count from around 70 Atari games and 30 Sega games to over 1,000 games across a variety of backing emulators. We’re also releasing the tool we use to add new games to the platform.', 'We’re releasing the full version of Gym Retro, a platform for reinforcement learning research on games. This brings our publicly-released game count from around 70 Atari games and 30 Sega games to over 1,000 games across a variety of backing emulators. We’re also releasing the tool we use to add new games to the platform.', 14, 'OpenAI Blog', 'https://openai.com/index/gym-retro', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-05-25 07:00:00.000000', '2026-04-07 06:56:48.312152', 'https://openai.com/index/gym-retro', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1022, 'AI and compute', 'We’re releasing an analysis showing that since 2012, the amount of compute used in the largest AI training runs has been increasing exponentially with a 3.4-month doubling time (by comparison, Moore’s Law had a 2-year doubling period)[^footnote-correction]. Since 2012, this metric has grown by more than 300,000x (a 2-year doubling period would yield only a 7x increase). Improvements in compute have been a key component of AI progress, so as long as this trend continues, it’s worth preparing for ', 'We’re releasing an analysis showing that since 2012, the amount of compute used in the largest AI training runs has been increasing exponentially with a 3.4-month doubling time (by comparison, Moore’s Law had a 2-year doubling period)[^footnote-correction]. Since 2012, this metric has grown by more than 300,000x (a 2-year doubling period would yield only a 7x increase). Improvements in compute have been a key component of AI progress, so as long as this trend continues, it’s worth preparing for the implications of systems far outside today’s capabilities.', 14, 'OpenAI Blog', 'https://openai.com/index/ai-and-compute', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-05-16 07:00:00.000000', '2026-04-07 06:56:48.312162', 'https://openai.com/index/ai-and-compute', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1023, 'AI safety via debate', 'We’re proposing an AI safety technique which trains agents to debate topics with one another, using a human to judge who wins.', 'We’re proposing an AI safety technique which trains agents to debate topics with one another, using a human to judge who wins.', 14, 'OpenAI Blog', 'https://openai.com/index/debate', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Safety & Alignment"]', '2018-05-03 07:00:00.000000', '2026-04-07 06:56:48.312172', 'https://openai.com/index/debate', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1024, 'Evolved Policy Gradients', 'We’re releasing an experimental metalearning approach called Evolved Policy Gradients, a method that evolves the loss function of learning agents, which can enable fast training on novel tasks. Agents trained with EPG can succeed at basic tasks at test time that were outside their training regime, like learning to navigate to an object on a different side of the room from where it was placed during training.', 'We’re releasing an experimental metalearning approach called Evolved Policy Gradients, a method that evolves the loss function of learning agents, which can enable fast training on novel tasks. Agents trained with EPG can succeed at basic tasks at test time that were outside their training regime, like learning to navigate to an object on a different side of the room from where it was placed during training.', 14, 'OpenAI Blog', 'https://openai.com/index/evolved-policy-gradients', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-04-18 07:00:00.000000', '2026-04-07 06:56:48.312182', 'https://openai.com/index/evolved-policy-gradients', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1025, 'Gotta Learn Fast: A new benchmark for generalization in RL', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/gotta-learn-fast', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-04-10 07:00:00.000000', '2026-04-07 06:56:48.312192', 'https://openai.com/index/gotta-learn-fast', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1026, 'Retro Contest', 'We’re launching a transfer learning contest that measures a reinforcement learning algorithm’s ability to generalize from previous experience.', 'We’re launching a transfer learning contest that measures a reinforcement learning algorithm’s ability to generalize from previous experience.', 14, 'OpenAI Blog', 'https://openai.com/index/retro-contest', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2018-04-05 07:00:00.000000', '2026-04-07 06:56:48.312201', 'https://openai.com/index/retro-contest', 0.0, 0);
