INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1104, 'OpenAI technical goals', 'OpenAI’s mission is to build safe AI, and ensure AI’s benefits are as widely and evenly distributed as possible.', 'OpenAI’s mission is to build safe AI, and ensure AI’s benefits are as widely and evenly distributed as possible.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-technical-goals', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2016-06-20 07:00:00.000000', '2026-04-07 06:56:48.312971', 'https://openai.com/index/openai-technical-goals', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1105, 'Generative models', 'This post describes four projects that share a common theme of enhancing or using generative models, a branch of unsupervised learning techniques in machine learning. In addition to describing our work, this post will tell you a bit more about generative models: what they are, why they are important, and where they might be going.', 'This post describes four projects that share a common theme of enhancing or using generative models, a branch of unsupervised learning techniques in machine learning. In addition to describing our work, this post will tell you a bit more about generative models: what they are, why they are important, and where they might be going.', 14, 'OpenAI Blog', 'https://openai.com/index/generative-models', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Research"]', '2016-06-16 07:00:00.000000', '2026-04-07 06:56:48.312981', 'https://openai.com/index/generative-models', 0.0, 0);
