INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1244, '业内人士认为碳酸锂价格出现短期回调', '连日来，碳酸锂期货价格持续回调。截至4月3日，主力合约报收156960元/吨，跌幅1.42%。业内人士认为，碳酸锂价格出现短期回调，主要诱因是锂供应端扰动再度发酵。近日，市场有消息称，中矿资源已获得津巴布韦锂精矿出口配额。对此，中矿资源证券部工作人员对记者表示，目前公司仍在与津巴布韦当地政府沟通，已有一些进展，但暂时没有明确的时间节点。市场普遍预期，相关出口细则有望在4月落地敲定。（科创板日报）', '连日来，碳酸锂期货价格持续回调。截至4月3日，主力合约报收156960元/吨，跌幅1.42%。业内人士认为，碳酸锂价格出现短期回调，主要诱因是锂供应端扰动再度发酵。近日，市场有消息称，中矿资源已获得津巴布韦锂精矿出口配额。对此，中矿资源证券部工作人员对记者表示，目前公司仍在与津巴布韦当地政府沟通，已有一些进展，但暂时没有明确的时间节点。市场普遍预期，相关出口细则有望在4月落地敲定。（科创板日报）', 8, '36氪', 'https://36kr.com/newsflashes/3754963659899396?f=rss', '', 'industry', '["\u79d1\u6280", "\u521b\u4e1a", "\u6295\u8d44"]', '2026-04-06 06:33:25.000000', '2026-04-07 06:26:55.682550', 'https://36kr.com/newsflashes/3754963659899396?f=rss', 0.0, 0);
